#!/usr/bin/env bash
# Ultra Terminal - macOS installer (self-extracting)
set -e

INSTALL_DIR="$HOME/.local/share/UltraTerminal"
BIN_DIR="$HOME/.local/bin"
APP_LINK="$BIN_DIR/ut"

mkdir -p "$INSTALL_DIR" "$BIN_DIR"

echo "Installing Ultra Terminal to $INSTALL_DIR..."

UT_SH_B64=''
RUNTIMES_B64=''

if command -v base64 >/dev/null 2>&1; then
    echo "$UT_SH_B64"     | base64 -d > "$INSTALL_DIR/ut.sh"
    echo "$RUNTIMES_B64"  | base64 -d > "$INSTALL_DIR/runtimes.json"
elif command -v openssl >/dev/null 2>&1; then
    echo "$UT_SH_B64"     | openssl base64 -d -A > "$INSTALL_DIR/ut.sh"
    echo "$RUNTIMES_B64"  | openssl base64 -d -A > "$INSTALL_DIR/runtimes.json"
else
    echo "ERROR: need 'base64' or 'openssl'."
    exit 1
fi

chmod +x "$INSTALL_DIR/ut.sh"
cat > "$APP_LINK" <<EOF
#!/usr/bin/env bash
exec "$INSTALL_DIR/ut.sh" "\$@"
EOF
chmod +x "$APP_LINK"

case ":$PATH:" in
    *":$BIN_DIR:"*) ;;
    *) echo ""; echo "WARN: $BIN_DIR not in PATH. Add: export PATH=\"$BIN_DIR:\$PATH\"" ;;
esac

echo ""
echo "OK! Run: ut"
echo "Uninstall: rm -rf $INSTALL_DIR $APP_LINK"